import { mkdirSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';

const requestedBrowser = process.env.TARGET_BROWSER ?? 'chrome';
const targetFamily = requestedBrowser === 'firefox' ? 'firefox' : 'chromium';
const generatedDir = join(process.cwd(), 'src', 'generated');
const offscreenRuntimePath = join(process.cwd(), 'src', 'offscreen', 'runtime.ts');

mkdirSync(generatedDir, { recursive: true });

const banner = [
  '// This file is generated by scripts/sync-browser-shells.mjs.',
  `// TARGET_BROWSER=${requestedBrowser}`,
  '',
].join('\n');

writeFileSync(
  join(generatedDir, 'background-shell.ts'),
  `${banner}export { registerBackgroundShell } from '../background/background-shell.${targetFamily}';\n`,
  'utf8',
);

writeFileSync(
  join(generatedDir, 'heavy-worker-client.ts'),
  `${banner}export {\n  __resetOffscreenAdapterForTests,\n  initializeHeavyWorkerMessaging,\n  sendToHeavyWorker,\n} from '../shared/heavy-worker-client.${targetFamily}';\n`,
  'utf8',
);

writeFileSync(
  offscreenRuntimePath,
  `${banner}export * from './runtime.${targetFamily}';\n`,
  'utf8',
);

console.log(`Synced browser shells for ${requestedBrowser} (${targetFamily})`);
